#nullable enable

using System.Threading;
using System.Threading.Tasks;
using FastEndpoints;
using HappyPumi.Api.CloudSetup;
using HappyPumi.Api.Contracts;

namespace HappyPumi.Api.Endpoints.CloudSetup;

/// <summary>
/// InitiateOAuth — mints an OAuth session (its id doubles as the <c>state</c>) for the requested cloud
/// provider and returns the provider's authorization URL. The URL is empty when the provider is unconfigured.
/// </summary>
public sealed class InitiateOAuthEndpoint(ICloudSetupProviderRegistry registry, ICloudOAuthSessionStore sessions)
    : EndpointWithoutRequest<InitiateOAuthResponse>
{
    public override void Configure()
    {
        Post("/api/esc/cloudsetup/{orgName}/oauth/initiate");
        AllowAnonymous();
        Description(b => b
            .WithTags("CloudSetup")
            .WithSummary("InitiateOAuth")
            .WithDescription("Initiates OAuth flow for a given cloud provider")
            .WithName("InitiateOAuth")
        );
    }

    public override async Task HandleAsync(CancellationToken ct)
    {
        var org = Route<string>("orgName")!;
        var body = await CloudSetupBody.ReadAsync(HttpContext, ct);
        var provider = CloudSetupBody.Str(body, "provider");
        var resolved = provider is null ? null : registry.For(provider);
        if (resolved is null)
        {
            AddError($"Unknown cloud provider '{provider}'. Expected one of: aws, azure, gcp.", "provider");
            await Send.ErrorsAsync(400, ct);
            return;
        }

        var returnUrl = CloudSetupBody.Str(body, "returnUrl");
        var sessionId = sessions.Create(org, resolved.Key, returnUrl);
        await Send.OkAsync(new InitiateOAuthResponse
        {
            SessionId = sessionId,
            Url = resolved.BuildAuthorizationUrl(sessionId, returnUrl),
        }, ct);
    }
}
